type CheckoutEvent = { orderId: string; idempotencyKey: string; emittedAt: string };

interface JobQueue {
  enqueue(topic: 'notify' | 'analytics', e: CheckoutEvent): Promise<void>;
}

export async function handleCheckout(input: CheckoutInput): Promise<CheckoutResult> {
  const order = await serviceA.write(input);
  const event: CheckoutEvent = { orderId: order.id, idempotencyKey: `${order.id}:checkout`, emittedAt: nowIso() };
  await Promise.all([queue.enqueue('notify', event), queue.enqueue('analytics', event)]);
  return { orderId: order.id };
}
